  1	import {
  2	  Button,
  3	  DatePicker,
  4	  Flex,
  5	  FlexItem,
  6	  isValidDate,
  7	  Text,
  8	  TextContent,
  9	  TextVariants,
 10	  TimePicker,
 11	  Tooltip
 12	} from '@patternfly/react-core';
 13	import * as _ from 'lodash';
 14	import * as React from 'react';
 15	import { useTranslation } from 'react-i18next';
 16	import { TimeRange, toISODateString, twentyFourHourTime } from '../../utils/datetime';
 17	import { formatDuration, getDateMsInSeconds, getDateSInMiliseconds } from '../../utils/duration';
 18	import Modal from './modal';
 19	import './time-range-modal.css';
 20	
 21	export interface TimeRangeModalProps {
 22	  maxChunkAge?: number;
 23	  isModalOpen: boolean;
 24	  setModalOpen: (v: boolean) => void;
 25	  range?: TimeRange;
 26	  setRange: (r: TimeRange) => void;
 27	  id?: string;
 28	}
 29	
 30	export const TimeRangeModal: React.FC<TimeRangeModalProps> = ({
 31	  id,
 32	  isModalOpen,
 33	  setModalOpen,
 34	  range,
 35	  setRange,
 36	  maxChunkAge
 37	}) => {
 38	  const { t } = useTranslation('plugin__netobserv-plugin');
 39	  const [error, setError] = React.useState<string | undefined>();
 40	  const [fromDate, setFromDate] = React.useState<string | undefined>();
 41	  const [fromTime, setFromTime] = React.useState<string>('');
 42	  const [toDate, setToDate] = React.useState<string | undefined>();
 43	  const [toTime, setToTime] = React.useState<string>('');
 44	
 45	  const dateValidator = React.useCallback(
 46	    (isFrom: boolean, date: Date): string => {
 47	      const otherDate = isFrom ? toDate : fromDate;
 48	      const d = otherDate ? new Date(Date.parse(otherDate)) : undefined;
 49	      if (isFrom && date > new Date()) {
 50	        return t('From date cannot be in the future');
 51	      }
 52	      return !d || !isValidDate(d) || (!isFrom && date >= d) || (isFrom && date <= d)
 53	        ? ''
 54	        : t('To date must be after From date');
 55	    },
 56	    [fromDate, t, toDate]
 57	  );
 58	
 59	  //this is a hack to allow user to type into date / time inputs without having to delete previous content
 60	  const onInput = (e: React.FormEvent<HTMLDivElement>, type: 'date' | 'time') => {
 61	    const input = e.target as HTMLInputElement;
 62	    const inputEvent = e.nativeEvent as InputEvent;
 63	
 64	    //save cursor position
 65	    let start = input.selectionStart as number;
 66	    let end = input.selectionEnd as number;
 67	
 68	    //split date / time accordingly
 69	    const delimiter = type === 'date' ? '-' : ':';
 70	    const valueParts = input.value.split(delimiter);
 71	
 72	    //hack delimiters only when caracters are added one by one
 73	    if (start === end && inputEvent.inputType === 'insertText' && inputEvent.data !== delimiter) {
 74	      //new caracter has been added before the delimiter, we need to move it to the next part
 75	      switch (type) {
 76	        case 'date':
 77	          if (start === 5 && valueParts.length > 1) {
 78	            valueParts[1] = inputEvent.data + valueParts[1];
 79	            start++;
 80	          } else if (start === 8 && valueParts.length > 2) {
 81	            valueParts[2] = inputEvent.data + valueParts[2];
 82	            start++;
 83	          }
 84	          break;
 85	        case 'time':
 86	          if (start === 3 && valueParts.length > 1) {
 87	            valueParts[1] = inputEvent.data + valueParts[1];
 88	            start++;
 89	          } else if (start === 6 && valueParts.length > 2) {
 90	            valueParts[2] = inputEvent.data + valueParts[2];
 91	            start++;
 92	          }
 93	          break;
 94	      }
 95	      end = start;
 96	    }
 97	
 98	    let truncatedValue = '';
 99	    for (let i = 0; i < 3; i++) {
100	      if (truncatedValue.length) {
101	        truncatedValue += delimiter;
102	      }
103	
104	      const isYear = type === 'date' && i === 0;
105	      if (valueParts.length > i) {
106	        const len = isYear ? 4 : 2;
107	        truncatedValue += valueParts[i].slice(0, len).padEnd(len, '0');
108	      } else {
109	        truncatedValue += isYear ? '0000' : '00';
110	      }
111	    }
112	
113	    //update input value
114	    input.value = truncatedValue;
115	
116	    //restore position
117	    input.setSelectionRange(start, end);
118	  };
119	
120	  const reloadInputs = React.useCallback(
121	    (reset = false) => {
122	      let from: Date;
123	      let to: Date;
124	      if (!reset && range && !Number.isNaN(range.from) && !Number.isNaN(range.to)) {
125	        from = new Date(getDateSInMiliseconds(range.from));
126	        to = new Date(getDateSInMiliseconds(range.to));
127	      } else {
128	        from = new Date();
129	        to = new Date();
130	        from.setHours(0, 0, 0, 0);
131	        to.setHours(23, 59, 0, 0);
132	      }
133	
134	      setFromDate(toISODateString(from));
135	      setFromTime(twentyFourHourTime(from, true));
136	      setToDate(toISODateString(to));
137	      setToTime(twentyFourHourTime(to, true));
138	    },
139	    [range]
140	  );
141	
142	  const onCancel = React.useCallback(() => {
143	    reloadInputs();
144	    setModalOpen(false);
145	  }, [reloadInputs, setModalOpen]);
146	
147	  const onSave = React.useCallback(() => {
148	    //update time inputs
149	    const from = getDateMsInSeconds(Date.parse(`${fromDate} ${fromTime}`));
150	    const to = getDateMsInSeconds(Date.parse(`${toDate} ${toTime}`));
151	    setRange({ from, to });
152	  }, [fromDate, fromTime, setRange, toDate, toTime]);
153	
154	  const getDateTimePickers = React.useCallback(() => {
155	    if (fromDate && fromTime && toDate && toTime) {
156	      return (
157	        <Flex className="date-time-pickers-container" direction={{ default: 'column' }}>
158	          <FlexItem>
159	            <Text component={TextVariants.h4}>{t('From')}</Text>
160	            <Flex direction={{ default: 'row' }} className="time-range-row">
161	              <FlexItem>
162	                <DatePicker
163	                  data-test="from-date-picker"
164	                  validators={[date => dateValidator(true, date)]}
165	                  //arguments positions are changing according to PF version
166	                  onChange={(e: unknown, v: unknown) => setFromDate(typeof e === 'string' ? String(e) : String(v))}
167	                  onInput={e => onInput(e, 'date')}
168	                  value={fromDate}
169	                  appendTo={() => document.body}
170	                />
171	              </FlexItem>
172	              <FlexItem>
173	                <TimePicker
174	                  data-test="from-time-picker"
175	                  is24Hour
176	                  includeSeconds
177	                  placeholder="hh:mm:ss"
178	                  delimiter=":"
179	                  //arguments positions are changing according to PF version
180	                  onChange={(e: unknown, t: unknown) => setFromTime(typeof e === 'string' ? String(e) : String(t))}
181	                  onInput={e => onInput(e, 'time')}
182	                  time={fromTime}
183	                  menuAppendTo={() => document.body}
184	                />
185	              </FlexItem>
186	            </Flex>
187	          </FlexItem>
188	          <FlexItem>
189	            <Text component={TextVariants.h4}>{t('To')}</Text>
190	            <Flex direction={{ default: 'row' }} className="time-range-row">
191	              <FlexItem>
192	                <DatePicker
193	                  data-test="to-date-picker"
194	                  validators={[date => dateValidator(false, date)]}
195	                  rangeStart={fromDate ? new Date(Date.parse(fromDate)) : undefined}
196	                  //arguments positions are changing according to PF version
197	                  onChange={(e: unknown, v: unknown) => setToDate(typeof e === 'string' ? String(e) : String(v))}
198	                  onInput={e => onInput(e, 'date')}
199	                  value={toDate}
200	                  appendTo={() => document.body}
201	                />
202	              </FlexItem>
203	              <FlexItem>
204	                <TimePicker
205	                  data-test="to-time-picker"
206	                  is24Hour
207	                  includeSeconds
208	                  placeholder="hh:mm:ss"
209	                  delimiter=":"
210	                  //arguments positions are changing according to PF version
211	                  onChange={(e: unknown, t: unknown) => setToTime(typeof e === 'string' ? String(e) : String(t))}
212	                  onInput={e => onInput(e, 'time')}
213	                  time={toTime}
214	                  menuAppendTo={() => document.body}
215	                />
216	              </FlexItem>
217	            </Flex>
218	          </FlexItem>
219	        </Flex>
220	      );
221	    }
222	    return <></>;
223	  }, [dateValidator, fromDate, fromTime, t, toDate, toTime]);
224	
225	  React.useEffect(() => {
226	    const from = new Date(Date.parse(`${fromDate} ${fromTime}`));
227	    const to = new Date(Date.parse(`${toDate} ${toTime}`));
228	    if (!isValidDate(from) || !isValidDate(to)) {
229	      setError(t('Invalid date / time'));
230	    } else if (from > new Date()) {
231	      setError(t('From date cannot be in the future'));
232	    } else if (to.getTime() < from.getTime()) {
233	      setError(t('To date must be after From date'));
234	    } else {
235	      setError(undefined);
236	    }
237	  }, [fromDate, fromTime, t, toDate, toTime]);
238	
239	  //set date / time at first start
240	  React.useEffect(() => {
241	    if (!fromDate || !fromTime || !toDate || !toTime) {
242	      reloadInputs();
243	    }
244	  }, [fromDate, fromTime, reloadInputs, toDate, toTime]);
245	
246	  return (
247	    <Modal
248	      id={id}
249	      title={t('Custom time range')}
250	      isOpen={isModalOpen}
251	      scrollable={false}
252	      onClose={() => onCancel()}
253	      footer={
254	        <>
255	          <Button data-test="time-range-reset" key="reset" variant="link" onClick={() => reloadInputs(true)}>
256	            {t('Reset')}
257	          </Button>
258	          <Button data-test="time-range-cancel" key="cancel" variant="link" onClick={() => onCancel()}>
259	            {t('Cancel')}
260	          </Button>
261	          <Tooltip
262	            //css hide tooltip here to avoid render issue
263	            className={'time-range-tooltip' + (_.isEmpty(error) ? '-empty' : '')}
264	            content={error}
265	            isVisible={error !== undefined}
266	          >
267	            <Button
268	              data-test="time-range-save"
269	              isDisabled={error !== undefined}
270	              key="confirm"
271	              variant="primary"
272	              onClick={() => onSave()}
273	            >
274	              {t('Save')}
275	            </Button>
276	          </Tooltip>
277	        </>
278	      }
279	    >
280	      <TextContent>
281	        <Text component={TextVariants.p}>
282	          {t('Select a custom time range. Flows are selected based on their End Time value.')}
283	        </Text>
284	      </TextContent>
285	      {getDateTimePickers()}
286	      {maxChunkAge && (
287	        <TextContent>
288	          <Text component={TextVariants.blockquote}>
289	            {t(
290	              'Collection latency could be up to {{maxChunkAge}} corresponding to the current Loki "max_chunk_age" ingester configuration.',
291	              { maxChunkAge: formatDuration(maxChunkAge) }
292	            )}
293	          </Text>
294	        </TextContent>
295	      )}
296	    </Modal>
297	  );
298	};
299	
300	export default TimeRangeModal;

