  1	import { act, fireEvent, render } from '@testing-library/react';
  2	import * as React from 'react';
  3	
  4	import { TimeRange } from '../../../utils/datetime';
  5	import TimeRangeModal, { TimeRangeModalProps } from '../time-range-modal';
  6	
  7	describe('<TimeRangeModal />', () => {
  8	  const props: TimeRangeModalProps = {
  9	    isModalOpen: true,
 10	    setModalOpen: jest.fn(),
 11	    range: undefined,
 12	    setRange: jest.fn(),
 13	    id: 'time-range-modal'
 14	  };
 15	
 16	  beforeEach(() => {
 17	    jest.useFakeTimers();
 18	    jest.clearAllMocks();
 19	  });
 20	
 21	  afterEach(() => {
 22	    jest.runOnlyPendingTimers();
 23	    jest.useRealTimers();
 24	  });
 25	
